	('932b6e98-8a43-483e-aa41-dc9e707509c4', 'arts_psychology', 'knowledge', NULL, '[{"id": 1, "type": "mcq", "options": ["Realism", "Surrealism", "Impressionism", "Abstract Expressionism"], "question": "Which art form is most directly associated with exploring the subconscious mind, as influenced by Freudian psychology?", "skill_tag": "Art History", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "easy", "stream_name": "Arts with Psychology", "correct_answer": "Surrealism"}, {"id": 2, "type": "mcq", "options": ["Color Palette", "Composition", "Subject Matter", "Texture"], "question": "The Gestalt principles of perception primarily influence which element of visual art?", "skill_tag": "Visual Perception", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "easy", "stream_name": "Arts with Psychology", "correct_answer": "Composition"}, {"id": 3, "type": "mcq", "options": ["Art Therapy", "Visual Communication", "Creative Expression", "Aesthetic Appreciation"], "question": "What is the term for using art as a therapeutic technique to improve mental and emotional well-being?", "skill_tag": "Art Therapy", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "easy", "stream_name": "Arts with Psychology", "correct_answer": "Art Therapy"}, {"id": 4, "type": "mcq", "options": ["Color Symbolism", "Cognitive Dissonance", "Classical Conditioning", "Emotional Regulation"], "question": "An artist uses vibrant, contrasting colors to evoke feelings of excitement and energy. Which psychological concept is the artist primarily utilizing?", "skill_tag": "Color Psychology", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "medium", "stream_name": "Arts with Psychology", "correct_answer": "Color Symbolism"}, {"id": 5, "type": "mcq", "options": ["It would emphasize the importance of physical proximity regardless of emotional connection.", "It would influence the depiction of characters'' behaviors and interactions based on their attachment styles.", "It would focus solely on the genetic inheritance of personality traits.", "It would promote the idea that early childhood experiences have no lasting impact."], "question": "How might an understanding of attachment theory inform the portrayal of parent-child relationships in a play or film?", "skill_tag": "Attachment Theory", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "medium", "stream_name": "Arts with Psychology", "correct_answer": "It would influence the depiction of characters'' behaviors and interactions based on their attachment styles."}, {"id": 6, "type": "mcq", "options": ["It can lead viewers to accept all information presented as factual.", "It can cause viewers to seek out and favor information that confirms their existing beliefs.", "It can make viewers more objective and open-minded.", "It has no impact on how viewers interpret information."], "question": "How can the psychological concept of ''confirmation bias'' affect an audience''s interpretation of a documentary film?", "skill_tag": "Cognitive Bias", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "medium", "stream_name": "Arts with Psychology", "correct_answer": "It can cause viewers to seek out and favor information that confirms their existing beliefs."}, {"id": 7, "type": "mcq", "options": ["Featuring a celebrity endorsement.", "Repeatedly showing the product throughout the commercial.", "Using persuasive language to highlight the product''s benefits.", "Creating a sense of urgency by limiting the product''s availability."], "question": "A director wants to use the ''mere-exposure effect'' to make a new product seem more appealing in a commercial. What strategy would be most effective?", "skill_tag": "Mere Exposure Effect", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "medium", "stream_name": "Arts with Psychology", "correct_answer": "Repeatedly showing the product throughout the commercial."}, {"id": 8, "type": "mcq", "options": ["By creating characters with perfectly consistent beliefs and actions.", "By presenting characters who experience internal conflict due to contradictory beliefs or actions.", "By simplifying complex moral dilemmas into easily digestible choices.", "By avoiding any portrayal of psychological discomfort or internal conflict."], "question": "How might the understanding of ''cognitive dissonance'' be used to create a compelling narrative in a novel or film?", "skill_tag": "Cognitive Dissonance", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "medium", "stream_name": "Arts with Psychology", "correct_answer": "By presenting characters who experience internal conflict due to contradictory beliefs or actions."}, {"id": 9, "type": "mcq", "options": ["Social Learning Theory", "Schema Theory", "Operant Conditioning", "Evolutionary Psychology"], "question": "An artist creates an installation that aims to deconstruct societal norms using visual metaphors. Which psychological theory is most applicable to understanding the audience''s processing of this artwork?", "skill_tag": "Schema Theory", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "hard", "stream_name": "Arts with Psychology", "correct_answer": "Schema Theory"}, {"id": 10, "type": "mcq", "options": ["Pre-conventional", "Conventional", "Post-conventional", "Instrumental Relativist"], "question": "A playwright aims to portray the complexities of moral decision-making during wartime, drawing heavily on Kohlberg''s stages of moral development. Which stage would a character be operating from if they disobeyed orders based on their own deeply held ethical principles, even at great personal risk?", "skill_tag": "Moral Development", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "hard", "stream_name": "Arts with Psychology", "correct_answer": "Post-conventional"}, {"id": 1, "type": "mcq", "options": ["Gestalt Principles", "Opponent-Process Theory", "Classical Conditioning", "Cognitive Dissonance", "Opponent-Process Theory"], "question": "Which psychological concept best explains why artists might use complementary colors to create visual excitement?", "skill_tag": "Color Theory", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "easy", "stream_name": "Arts with Psychology", "correct_answer": "Opponent-Process Theory"}, {"id": 2, "type": "mcq", "options": ["Need for Closure", "Self-Actualization", "Ego Defense", "Catharsis"], "question": "An artist using repetitive patterns in their work may be unconsciously addressing which psychological need?", "skill_tag": "Motivation", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "easy", "stream_name": "Arts with Psychology", "correct_answer": "Need for Closure"}, {"id": 3, "type": "mcq", "options": ["Figure-ground relationship", "Operant conditioning", "The uncanny valley", "Cognitive appraisal"], "question": "Which of the following is a core concept of Gestalt psychology that can be found in visual art?", "skill_tag": "Gestalt Psychology", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "easy", "stream_name": "Arts with Psychology", "correct_answer": "Figure-ground relationship"}, {"id": 4, "type": "mcq", "options": ["By using only primary colors", "By applying linear perspective and atmospheric perspective", "By avoiding any recognizable shapes", "By creating a perfectly symmetrical composition"], "question": "How might an artist subtly manipulate the viewer''s perception of depth in a two-dimensional painting?", "skill_tag": "Visual Perception", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "medium", "stream_name": "Arts with Psychology", "correct_answer": "By applying linear perspective and atmospheric perspective"}, {"id": 5, "type": "mcq", "options": ["Confirmation Bias", "Facial Action Coding System (FACS)", "The Bystander Effect", "Fundamental Attribution Error"], "question": "An artist creates a series of portraits where each subject displays a slightly different emotion. What psychological principle is the artist likely exploring?", "skill_tag": "Emotion Recognition", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "medium", "stream_name": "Arts with Psychology", "correct_answer": "Facial Action Coding System (FACS)"}, {"id": 6, "type": "mcq", "options": ["It explains why artists are always depressed", "It describes a state of deep focus and immersion that enhances artistic performance", "It suggests that artists are inherently narcissistic", "It means artists are always procrastinating"], "question": "How could the concept of ''flow state'' relate to an artist''s creative process?", "skill_tag": "Flow State", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "medium", "stream_name": "Arts with Psychology", "correct_answer": "It describes a state of deep focus and immersion that enhances artistic performance"}, {"id": 7, "type": "mcq", "options": ["Operant Conditioning", "Catharsis", "Cognitive Appraisal", "Social Comparison Theory"], "question": "Which psychological theory explains why viewing a piece of art that expresses intense sadness might evoke a feeling of relief in the viewer?", "skill_tag": "Emotional Regulation", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "medium", "stream_name": "Arts with Psychology", "correct_answer": "Catharsis"}, {"id": 8, "type": "mcq", "options": ["By only using black and white", "By strategically placing related images or words near their artwork", "By creating abstract and ambiguous compositions", "By making the artwork as large as possible"], "question": "How might an artist use the principles of ''priming'' to influence a viewer''s interpretation of their artwork?", "skill_tag": "Cognitive Bias", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "medium", "stream_name": "Arts with Psychology", "correct_answer": "By strategically placing related images or words near their artwork"}, {"id": 9, "type": "mcq", "options": ["By making the sculpture extremely heavy and difficult to move", "By using materials and forms that mimic physical sensations associated with that emotion", "By hiding the sculpture in an obscure location", "By creating a sculpture that is perfectly symmetrical and balanced"], "question": "How could an artist utilize principles of ''embodied cognition'' to create a sculpture that evokes a specific emotional response in viewers?", "skill_tag": "Embodied Cognition", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "hard", "stream_name": "Arts with Psychology", "correct_answer": "By using materials and forms that mimic physical sensations associated with that emotion"}, {"id": 10, "type": "mcq", "options": ["Behavioral Economics", "Cognitive Psychology", "Social Psychology", "Evolutionary Psychology"], "question": "An artist creates a series of interactive installations designed to challenge viewers'' assumptions about their own perception. What area of psychology is this artist most likely drawing upon?", "skill_tag": "Cognitive Biases", "stream_id": "arts_psychology", "created_at": "2026-02-01T14:43:05.444Z", "difficulty": "hard", "stream_name": "Arts with Psychology", "correct_answer": "Cognitive Psychology"}]', '2026-02-01 14:42:46.73529+00', true, '2026-02-01 14:43:05.444+00', '2026-02-01 14:42:46.73529+00', 'ab46b2ac-9922-4569-adc6-73eb6b645202', NULL, 'Grade 10'),
